/** Match a category name to an icon, or null → caller falls back to a monogram. */
export function iconForCategory(name?: string | null): string | null {
  if (!name) return null;
  const n = name.toLowerCase();
  if (n.includes("watch")) return categoryIcons.watch;
  if (n.includes("earring")) return categoryIcons.earrings;
  if (n.includes("anklet")) return categoryIcons.anklet;
  if (n.includes("necklace")) return categoryIcons.necklace;
  if (n.includes("bracelet") || n.includes("bangle") || n.includes("summer"))
    return categoryIcons.bracelet;
  if (n.includes("ring")) return categoryIcons.ring;
  return null;
}
